-- =============================================
-- SYNC BLOG POSTS TO LIVE - Run in Cloud > Database > Run SQL (Live)
-- =============================================

-- STEP 1: Insert ES posts (ON CONFLICT update)
ON CONFLICT (id) DO UPDATE SET
  title = EXCLUDED.title, slug = EXCLUDED.slug, excerpt = EXCLUDED.excerpt, image_url = EXCLUDED.image_url,
  category = EXCLUDED.category, tags = EXCLUDED.tags, author = EXCLUDED.author, language = EXCLUDED.language,
  published = EXCLUDED.published, published_at = EXCLUDED.published_at;

-- STEP 2: Insert PT posts (ON CONFLICT update)
ON CONFLICT (id) DO UPDATE SET
  title = EXCLUDED.title, slug = EXCLUDED.slug, excerpt = EXCLUDED.excerpt, image_url = EXCLUDED.image_url,
  category = EXCLUDED.category, tags = EXCLUDED.tags, author = EXCLUDED.author, language = EXCLUDED.language,
  published = EXCLUDED.published, published_at = EXCLUDED.published_at;

-- STEP 3: Update EN post categories (already exist in Live, just fix category names)
-- EN categories stay in English, no changes needed.

-- DONE! All ES and PT posts are now synced to Live.
