INSERT INTO public.blog_posts (id, title, slug, excerpt, image_url, category, tags, author, language, published, published_at)
VALUES
('8a5e44ee-3095-45ca-a748-7b9f9993bde3', 'Actualización de planes y nuevos estándares de calidad visual en Musicdibs', 'plan-update-and-new-visual-quality-standards-at-musicdibs-es', 'A partir del 15 de marzo, una serie de cambios entrarán en vigor en nuestros planes de suscripción y en el sistema de promoción de Musicdibs.', 'https://musicdibs.com/wp-content/uploads/2026/02/Comunicado-oficialMesa-de-trabajo-1-copia-8.png', 'Musicdibs', ARRAY['Musicdibs','Quality standards','Updates to plans'], 'Marta Escabias Trapero', 'es', true, '2026-02-25T00:00:00+00:00'),
('77369f18-4de3-4ba8-8897-bf868c7002df', 'Cómo migrar tu catálogo musical con Musicdibs', 'how-to-migrate-your-music-catalog-with-musicdibs-es', 'En una industria musical en constante evolución, tomar decisiones estratégicas es esencial para artistas, sellos y equipos de management.', 'https://musicdibs.com/wp-content/uploads/2026/01/Comunicado-Oficial-Mesa-de-trabajo-1-80.jpg', 'Distribución', ARRAY['Music Catalog','Musicdibs'], 'Marta Escabias Trapero', 'es', true, '2026-01-21T00:00:00+00:00'),
('274ea142-9162-48c3-b70a-0aedfa857840', 'Impulsa tu presencia en Spotify y TikTok con Musicdibs', 'boost-your-presence-on-spotify-and-tiktok-with-musicdibs-es', 'En Musicdibs, seguimos implementando mejoras para ayudarte a sacar el máximo provecho de tus lanzamientos y fortalecer tu visibilidad.', 'https://musicdibs.com/wp-content/uploads/2026/01/Articulo-178Mesa-de-trabajo-1-80.jpg', 'Distribución', ARRAY['music distribution','Musicdibs','Spotify','TikTok'], 'Marta Escabias Trapero', 'es', true, '2026-01-14T00:00:00+00:00'),
('e3772b12-608f-4222-ad44-b0bf12e6add2', 'Mejoras en el servicio de distribución de Musicdibs', 'improvements-to-the-musicdibs-distribution-service-es', 'En Musicdibs, seguimos evolucionando para ofrecer herramientas que te ayuden a desarrollar tu carrera musical de forma profesional y sostenible.', 'https://musicdibs.com/wp-content/uploads/2025/12/Comunicado-oficial-2Mesa-de-trabajo-1-copia-7-80.jpg', 'Distribución', ARRAY['DSP','Musicdibs'], 'Marta Escabias Trapero', 'es', true, '2025-12-30T00:00:00+00:00'),
('172d5087-9665-47f5-9333-9555526f89f5', 'Información importante para mejorar tus lanzamientos en Musicdibs', 'important-information-to-improve-your-releases-on-musicdibs-es', 'En Musicdibs, nuestra prioridad es garantizar que tu música llegue a las plataformas digitales sin contratiempos.', 'https://musicdibs.com/wp-content/uploads/2025/12/logo-iCommunityMesa-de-trabajo-1-copia-7-80.jpg', 'Distribución', ARRAY['Composer','Lyricist','Musicdibs','Producer'], 'Marta Escabias Trapero', 'es', true, '2025-12-23T00:00:00+00:00'),
('31c752fd-c8f3-4a51-8297-a8f6d9fd103d', 'Spotify: Modo Descubrimiento y penalizaciones', 'spotify-discovery-mode-and-penalties-es', 'En el ecosistema musical digital actual, Spotify se ha convertido en una plataforma esencial para artistas que quieren llegar a nuevos oyentes.', 'https://musicdibs.com/wp-content/uploads/2025/10/Articulo-176Mesa-de-trabajo-1-80.jpg', 'Distribución', ARRAY['Discovery Mode','Spotify','Spotify for Artists'], 'Marta Escabias Trapero', 'es', true, '2025-10-30T00:00:00+00:00'),
('9526e102-53fb-4fd1-ad37-2c9d9373dc87', 'YouTube Content ID: Qué es y cómo solicitarlo', 'youtube-content-id-what-it-is-and-how-to-request-it-es', 'Si distribuyes tu música online, probablemente hayas oído hablar de YouTube Content ID, una de las herramientas más potentes para proteger tus derechos.', 'https://musicdibs.com/wp-content/uploads/2025/10/Articulo-175Mesa-de-trabajo-1-80.jpg', 'Distribución', ARRAY['Musicdibs','Youtube','Youtube Content ID'], 'Marta Escabias Trapero', 'es', true, '2025-10-23T00:00:00+00:00'),
('b42e1922-40af-4b00-a1bf-d7e9cd6c4175', 'Qué es un Canal Oficial de Artista (OAC) en YouTube y cómo configurarlo', 'what-is-an-oac-on-youtube-and-how-to-set-it-up-es', 'YouTube ha lanzado su programa de Canal Oficial de Artista (OAC) para músicos, diseñado para centralizar todo tu contenido musical.', 'https://musicdibs.com/wp-content/uploads/2025/10/Articulo-174Mesa-de-trabajo-1-100.jpg', 'Distribución', ARRAY['Musicdibs','OAC','Official Artist Channel','YouTube Music'], 'Marta Escabias Trapero', 'es', true, '2025-10-16T00:00:00+00:00'),
('f3b3a0d6-b7dd-49e8-8355-88e1e1b670e5', 'Spotify: Cómo verificar tu perfil de artista', 'spotify-how-to-get-your-artist-profile-verified-es', 'Si eres músico, manager o parte de un sello discográfico, tener un perfil de artista verificado en Spotify te permite tomar el control directo.', 'https://musicdibs.com/wp-content/uploads/2025/10/Articulo-172Mesa-de-trabajo-1-80.jpg', 'Distribución', ARRAY['Spotify','Spotify for Artists'], 'Marta Escabias Trapero', 'es', true, '2025-10-08T00:00:00+00:00'),
('da74ef84-16bf-46f0-99a4-88c7bf55fbdb', 'Apple Music for Artists: Cómo reclamar tu perfil y aprovecharlo al máximo', 'apple-music-for-artists-how-to-claim-your-profile-es', 'Cuando distribuyes tu música con Musicdibs, uno de los pasos más importantes es asegurarte de que tu perfil en Apple Music esté correctamente configurado.', 'https://musicdibs.com/wp-content/uploads/2025/09/Articulo-171Mesa-de-trabajo-1-80.jpg', 'Distribución', ARRAY['Apple Music','Apple Music for Artists','Musicdibs'], 'Marta Escabias Trapero', 'es', true, '2025-09-18T00:00:00+00:00'),
('5ade67b6-5fdd-4538-bce7-b831b7cec809', 'Cómo obtener tu Apple Artist ID paso a paso', 'how-to-get-your-apple-artist-id-step-by-step-es', 'El Apple Artist ID es un identificador único que Apple asigna a cada artista en su plataforma.', 'https://musicdibs.com/wp-content/uploads/2025/09/170Mesa-de-trabajo-1-80-1.jpg', 'Distribución', ARRAY['Apple Artist ID','Apple Music','iTunes Store','Musicdibs'], 'Marta Escabias Trapero', 'es', true, '2025-09-11T00:00:00+00:00'),
('eecbacfd-5d41-4184-935e-1948c6e85cab', '¿Obra hecha con IA o por IA? Entiende la diferencia legal y cómo registrar tu creación', 'work-made-with-ai-or-by-ai-legal-difference-es', 'El uso de inteligencia artificial (IA) en la creación de obras artísticas crece cada día. Pero no todas las obras generadas con IA reciben el mismo tratamiento.', 'https://musicdibs.com/wp-content/uploads/2025/06/Mesa-de-trabajo-1-80-2.jpg', 'Música', ARRAY['Artificial Intelligence','copyright','Musicdibs','register songs'], 'Marta Escabias Trapero', 'es', true, '2025-07-09T00:00:00+00:00'),
('8ac62075-9b41-44d5-af36-128bf79abbc2', 'Musicdibs lanza su nueva función de distribución musical', 'musicdibs-launches-new-music-distribution-feature-es', 'En Musicdibs, siempre hemos creído que proteger tu música es el primer paso. Ahora, también te ayudamos a compartirla con el mundo.', 'https://musicdibs.com/wp-content/uploads/2025/06/Mesa-de-trabajo-1-80.jpg', 'Música', ARRAY['Blockchain','Emerging artists','music distribution','Musicdibs','streaming platforms'], 'Marta Escabias Trapero', 'es', true, '2025-07-02T00:00:00+00:00'),
('11fecdc2-0134-4613-bc05-a06fbdb864e9', 'Entrevista con Alba Mbengue: crecer sin perder la esencia', 'interview-with-alba-mbengue-es', 'Con una voz que conmueve y letras profundamente personales, Alba Mbengue está dejando huella en la escena musical actual.', 'https://musicdibs.com/wp-content/uploads/2025/06/DSC09993_-scaled-e1750755231949.jpeg', 'Entrevistas', ARRAY['Alba Mbengue','creative process','DEVA','Emerging artists','Musicdibs'], 'Marta Escabias Trapero', 'es', true, '2025-06-24T00:00:00+00:00'),
('e22b0df1-f72a-4522-a12d-c4e46b55387e', 'Mitos sobre los derechos de autor en la música', 'myths-about-copyright-in-music-es', 'En el mundo de la música, la creatividad va de la mano de la protección legal. Sin embargo, cuando se trata de derechos de autor, hay muchos mitos.', 'https://musicdibs.com/wp-content/uploads/2025/05/Mesa-de-trabajo-1-80-2.jpg', 'Música', ARRAY['copyright','Emerging artists','Legal validity','Musicdibs','register music'], 'Marta Escabias Trapero', 'es', true, '2025-05-29T00:00:00+00:00'),
('e09541c8-d872-4c22-9f7f-2d30c7452a89', 'Más de 400 artistas exigen protección de derechos de autor ante el auge de la IA', 'over-400-artists-demand-copyright-protection-ai-es', 'En mayo de 2025, más de 400 artistas británicos, incluyendo Elton John, Dua Lipa, Coldplay y Paul McCartney, firmaron una carta exigiendo protección.', 'https://musicdibs.com/wp-content/uploads/2025/05/Mesa-de-trabajo-1-80-1.jpg', 'Música', ARRAY['artificial intelligence','Blockchain','copyright','independent music','Musicdibs'], 'Marta Escabias Trapero', 'es', true, '2025-05-21T00:00:00+00:00'),
('4a27ff5a-43e3-4fba-8106-dcf5d4ba2b5c', 'Entrevista con Kyra: cómo nace su nueva etapa', 'interview-with-kyra-new-stage-es', 'Desde que tiene memoria, Kyra supo que su camino estaba en la música. Criada en Galicia, comenzó a cantar a una edad muy temprana.', 'https://musicdibs.com/wp-content/uploads/2025/05/592803ed-eda3-4a1d-a2a3-4188d6ad9823-1-e1747124000435.jpeg', 'Entrevistas', ARRAY['artistic evolution','BDP','Delaossa','Kyra','TikTok','urban music'], 'Marta Escabias Trapero', 'es', true, '2025-05-13T00:00:00+00:00'),
('60578df5-923b-42fb-a334-c90b3cf4a7dc', 'Cómo registrar una canción', 'how-to-register-a-song-es', '¿Eres músico, compositor o productor preocupado por que alguien use tu obra sin permiso? Entonces necesitas registrar tus canciones.', 'https://musicdibs.com/wp-content/uploads/2025/05/Mesa-de-trabajo-1-80.jpg', 'Música', ARRAY['Blockchain','copyright','Legal validity','Musicdibs','register music'], 'Marta Escabias Trapero', 'es', true, '2025-05-08T00:00:00+00:00'),
('ac571a9f-ac75-4f22-b319-0091f093ec4c', '¡DIBS cotiza en Biconomy! Un nuevo hito para Musicdibs', 'dibs-listed-on-biconomy-es', '¡DIBS ya cotiza en Biconomy! Un nuevo hito en el camino de Musicdibs hacia la descentralización musical.', 'https://musicdibs.com/wp-content/uploads/2025/03/GlSWsxvW0AAYV_P-e1741354046128.jpg', 'DIBS Token', ARRAY['Biconomy','DIBS','DIBS Token','Listed','Musicdibs'], 'Marta Escabias Trapero', 'es', true, '2025-03-07T00:00:00+00:00'),
('d4743ef5-b55a-41a5-8891-320411444a8f', 'Entrevista con Caracazador: el arte de hacer pop desde lo íntimo', 'interview-caracazador-es', 'Caracazador nos cuenta cómo transforma lo cotidiano en canciones pop con alma propia.', 'https://musicdibs.com/wp-content/uploads/2025/03/REPUBLICA-16-cSento-Soler-scaled-e1741946423748.jpg', 'Entrevistas', ARRAY['Art','Caracazador','Emerging artists','Pop','Zahara'], 'Marta Escabias Trapero', 'es', true, '2025-03-14T00:00:00+00:00'),
('382d49b1-1e4d-4f47-ba30-89f1d5ea3733', 'Entrevista con Alcalá Norte: de las salas pequeñas a conquistar festivales', 'interview-alcala-norte-es', 'Alcalá Norte nos cuenta su trayectoria desde las salas pequeñas hasta los grandes festivales.', 'https://musicdibs.com/wp-content/uploads/2025/02/Alcala-norte_primavera24_press_12-e1740671143313.jpg', 'Entrevistas', ARRAY['Alcalá Norte','Arenal Sound','Erentxun','Indie','Kase O'], 'Marta Escabias Trapero', 'es', true, '2025-02-27T00:00:00+00:00'),
('fec92c0d-4f19-4c72-951e-9ef640642138', '¡El token DIBS se listará el 1 de marzo!', 'dibs-token-listed-march-1-es', 'Tras una exitosa preventa, el token DIBS estará disponible para trading a partir del 1 de marzo.', 'https://musicdibs.com/wp-content/uploads/2025/02/Comunicado-oficial-Listado-DIBSMesa-de-trabajo-1-copia-4-80.jpg', 'DIBS Token', ARRAY['DIBS','DIBS Token','Listed','Musicdibs','Utility token'], 'Marta Escabias Trapero', 'es', true, '2025-02-10T00:00:00+00:00'),
('f87670ba-1b4c-4970-b0d9-746b9ec92d9a', 'Los errores más comunes al registrar derechos de autor musicales y cómo evitarlos', 'common-mistakes-registering-music-copyrights-es', 'Registrar los derechos de autor de tu música es fundamental, pero muchos artistas cometen errores que pueden costarles caro.', 'https://musicdibs.com/wp-content/uploads/2025/02/Articulo-155Mesa-de-trabajo-1-80.jpg', 'Música', ARRAY['copyright','Musicdibs','register'], 'Marta Escabias Trapero', 'es', true, '2025-02-06T00:00:00+00:00'),
