VALUES
('0ea222b1-f652-4d77-9183-d1c882d7394c', 'Atualização de planos e novos padrões de qualidade visual no Musicdibs', 'plan-update-and-new-visual-quality-standards-at-musicdibs-pt', 'A partir de 15 de março, uma série de mudanças entrará em vigor em nossos planos de assinatura e no sistema de promoção do Musicdibs.', 'https://musicdibs.com/wp-content/uploads/2026/02/Comunicado-oficialMesa-de-trabajo-1-copia-8.png', 'Musicdibs', ARRAY['Musicdibs','Quality standards','Updates to plans'], 'Marta Escabias Trapero', 'pt', true, '2026-02-25T00:00:00+00:00'),
